INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('5f10878b-742a-53e2-89b5-cacb531427bb', '6de21873-0b3a-4a85-96c8-30ec0e0d91ea', '___ am a boy.', '我是一個男孩。', 'I', 'He', 'She', 'You', 'I 是第一人稱單數主格。', '單獨一個 I 就是「我」。', '2026-07-05 11:48:08', '2026-07-05 11:48:08'),
('d3020f86-1c88-5c2e-9c3a-aba1b3a910c3', 'e89b4376-129f-4d76-bd81-d567a6a5f029', 'Although I ___ a bit nervous about the presentation, I have prepared thoroughly.', '雖然我對這次的簡報感到有點緊張，但我已經做了充分的準備。', 'am', 'do', 'have', 'make', 'am 在此作為連繫動詞，用來連結主詞 I 與形容詞 nervous。', 'I am + 形容詞，例如 I am happy。', '2026-07-06 20:31:52', '2026-07-06 20:31:52'),
('f3f026df-9ac0-5d3d-b9f2-af29698c9dc3', '6d385085-55ad-42de-8aaa-35aba883e660', 'If you know the correct solution, please ___ the teacher''s question directly.', '如果你知道正確的解答，請直接回答老師的問題。', 'answer', 'ignore', 'avoid', 'forget', '動詞用法，表示「回答」。', '看到問題 (Question) → 給予答案 (Answer)。', '2026-07-06 21:41:53', '2026-07-06 21:41:53'),
('c1046d4a-82a2-54d8-b24d-8b3afa95948f', 'c0568d00-7d56-49e5-ade7-844fbe54902f', 'She felt extremely ___ about her medical results, which is why she couldn''t sleep last night.', '她對自己的檢查結果感到非常焦慮，這就是為什麼她昨晚無法入睡。', 'anxious', 'content', 'indifferent', 'cheerful', 'anxi- 意指不安或困擾。', '心跳很快，感覺安(an)不下來(xi) → anxious 焦慮的。', '2026-07-06 22:00:42', '2026-07-06 22:00:42'),
('756b579a-9ddb-5529-b707-539d5d0b18b3', 'a9c32071-cd9f-4675-a8a3-770db4baa0aa', 'In many grammar guides, the term ''___'' is used as a common abbreviation for ''auxiliary''.', '在許多文法指南中，''___'' 被用作 ''auxiliary'' 的常見縮寫。', 'aux.', 'adj.', 'adv.', 'prep.', 'auxiliary 源自拉丁語 auxiliārius，意為「幫助、輔助」。', 'aux 是 auxiliary 的前三個字母，在文法中代表「助動詞」這個助手。', '2026-07-07 03:55:26', '2026-07-07 03:55:26'),
('4c01b98e-e4df-5705-9812-5856968f0483', '5d20b73d-7d29-498d-92b3-52636f5571d1', '___ I use your phone?', '我可以使用你的電話嗎？', 'Can', 'Must', 'Will', 'Should', '用於請求許可。', '可以用 can 來請求許可。', '2026-07-05 11:43:54', '2026-07-05 11:43:54'),
('39ba3aa0-11e3-5206-8405-caa6b7c4c77b', 'f683c9d8-1a0f-424e-9b36-77ebf72b0c78', 'He moves the small pieces to play ___.', '他移動小棋子來玩西洋棋。', 'chess', 'soccer', 'piano', 'tennis', 'chess 為名詞，意為西洋棋。', '下棋時要 check 棋子的位置 → chess。', '2026-07-07 03:36:54', '2026-07-07 03:36:54'),
('8db9164b-2ab9-55ee-8c81-6b2b0f430c3f', '3da0621e-682e-447a-b612-f1d1e0cfa9c4', 'The sudden change in the weather began to ___ the travelers.', '天氣的突然變化開始讓旅人們感到擔心。', 'concern', 'enjoy', 'forget', 'follow', 'con- (一起) + cern (篩選/辨別) → 原意為將事物放在一起觀察，引申為關心或使擔心。', 'con (一起) + cern (看) → 把目光放在一起看 → 關注、關心、使擔心。', '2026-07-07 09:19:48', '2026-07-07 09:19:48'),
('4d6a89f7-222c-57e4-9cd3-10a439553197', 'b420ee82-b316-4f57-81d0-09ec81a31efd', 'The ___ of the house is where people come in.', '房子的入口是人們進來的地方。', 'entrance', 'ceiling', 'floor', 'kitchen', 'enter (進入) + -ance (名詞字尾) → entrance (入口)', '記住 enter (進入) 加上名詞字尾 -ance 就變成「進入的地方」，即「入口」。', '2026-07-07 04:03:33', '2026-07-07 04:03:33'),
('cc1f68b6-a294-5688-865e-a6c3144a7c77', '0d503313-f24a-4195-8140-6fd95a400606', 'This is my robot. ___ can talk.', '這是我的機器人。___會說話。', 'it', 'he', 'she', 'you', '代名詞：用於替換前面提到的單數物品。', '機器人不是人，請用 it。', '2026-07-05 08:59:23', '2026-07-05 08:59:23'),
('0fcda612-c313-5625-8254-df4b28c8b09b', '69c72296-40c5-4d3c-8b3a-6a62df6576c3', 'I am very proud of ___ achievements in the recent competition.', '我為我在最近比賽中的成就感到非常自豪。', 'my', 'your', 'her', 'their', '所有格形容詞 (possessive adjective)', 'my + 名詞 → 我的...', '2026-07-05 14:13:13', '2026-07-05 14:13:13'),
('958ef92b-f394-5071-a837-a37491644bd7', '8fecc1f7-8571-4e65-874e-7bec724d9609', '___ students who finished the exam early were allowed to leave.', '提前完成考試的學生被允許離開。', 'The', 'A', 'Some', 'Any', '定冠詞 (Definite Article)', '指特定的那群人或事物用 the', '2026-07-05 10:22:35', '2026-07-05 10:22:35'),
('99e0d4ed-f8db-57e3-ae2c-16a6a84d4d8b', 'a6a15ed6-6715-4012-aca0-d203810bc834', 'I will never forget ___ moment of my life.', '我永遠不會忘記生命中的這個時刻。', 'this', 'any', 'each', 'some', '形容詞，用來修飾名詞，指代特定的時刻。', '指點眼前的東西用 this。', '2026-07-05 14:34:27', '2026-07-05 14:34:27'),
('ec20a184-fdc3-57fb-85dc-0be48041bf6f', '1f05e6cd-08a7-4cd3-8322-6f7534909238', 'It is ___ to go home now.', '現在是該回家的時候了。', 'time', 'way', 'place', 'food', '此為基礎單字，無特定字根。', 'It is time to... 是「是時候該做某事」的常用句型。', '2026-07-06 10:44:02', '2026-07-06 10:44:02');
